var e=[{id:`L3_1`,type:`narration`,speaker:null,text:{KOREA:`들리니, 발레리. 네가 만들던 곡이야.`,JPN:`聞こえる？　ヴァレリー。あなたが作っていた曲よ。`,ENG:`Do you hear that, Valeriy? It's the song you were writing.`,TWN:`你有聽到嗎，瓦萊里？這是你寫的曲子。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`narration`,speaker:null,text:{KOREA:`후반부는 아직 정하지 못했지만.`,JPN:`後半はまだ未完成だけど。`,ENG:`Although the latter half hasn't been decided yet.`,TWN:`不過後半段還沒有完成。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`SENA_HARMONY_NULL_NULL`,text:{KOREA:`비켜, 불량품!!`,JPN:`どけ、不良品！！`,ENG:`Out of my way, defect!!`,TWN:`讓開，瑕疵品！！`},stage:{bg:`WORKSHOP`,slots:{L:{char_id:`SENA_HARMONY_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L9_1`,type:`dialog`,speaker:`RIFLE_ADMIN_NAMED_NULL`,text:{KOREA:`부전대장님, 근접전을 벌이시면 엄호하기 어렵습니다! 이탈하십시오!`,JPN:`副戦隊長殿、近接戦になると援護が難しくなります！　離脱してください！`,ENG:`Deputy Commander, I can't cover you when you're in melee combat! Please fall back!`,TWN:`副戰隊長，你跟敵人太靠近的話，我不好掩護你！請保持距離！`},stage:{bg:`WORKSHOP`,slots:{L:{char_id:`SENA_HARMONY_NULL_NULL`,face:`UNIT_HATE`},C:{char_id:`RIFLE_ADMIN_NAMED_NULL`,face:`UNIT_IDLE`},R:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L10_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`머리에 총 맞았니? 틈을 주면 중사를 쫓아갈 거야!`,JPN:`頭でもぶつけちゃった？　隙を見せたら軍曹を追う機会を与えちゃうでしょ！`,ENG:`Did you take a bullet to the head? If I back off, she's going after Sergeant!`,TWN:`你腦袋有洞嗎？我不這樣的話，她就會趁隙去追中士！`},stage:{bg:`WORKSHOP`,slots:{L:{char_id:`SENA_HARMONY_NULL_NULL`,face:`UNIT_HATE`},C:{char_id:`RIFLE_ADMIN_NAMED_NULL`,face:`UNIT_IDLE`},R:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`여기서 끝장을 낸다! 더 이상 빠져나가게 내버려 두지 않아!`,JPN:`ここではっきり終わらせるの！　逃がすわけにはいかないわ！`,ENG:`We end it here! I won't let anymore slip through our grasp!`,TWN:`我要在這裡結束這一切！不能讓她再次溜走！`},stage:{bg:`WORKSHOP`,slots:{L:{char_id:`SENA_HARMONY_NULL_NULL`,face:`UNIT_HATE`},C:{char_id:`RIFLE_ADMIN_NAMED_NULL`,face:`UNIT_IDLE`},R:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L13_1`,type:`narration`,speaker:null,text:{KOREA:`알고 있어. 네 취향과 많이 다르다는 거.`,JPN:`わかってる。この曲があなたの好みじゃないってことは。`,ENG:`I already know. It's not to your taste.`,TWN:`我知道，這並不符合你的品味。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`narration`,speaker:null,text:{KOREA:`하지만 어쩔 수 없으려나. 곡에는 결국 연주하는 사람의 감정이 스며드니까.`,JPN:`でも仕方ないかな。曲には演奏者の感情が入り込んでしまうから。`,ENG:`But what else can I do? Music has its way of introducing the performer's emotions.`,TWN:`但沒辦法，演奏者的私人情緒始終會滲入到曲子裡。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`SENA_HARMONY_NULL_NULL`,text:{KOREA:`대체 뭐가 문제야? 뭐 때문에 이렇게 이 악물고 달려드는 거냐고!`,JPN:`いったい何のために？　ここまで必死になって飛びかかってくるのはどうしてよ！`,ENG:`What's wrong with you? Why are you so adamant on stopping me?!`,TWN:`到底為什麼？為什麼要追著我不放！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`SENA_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`SENA_HARMONY_NULL_NULL`,text:{KOREA:`실험체들 때문에 그래? 어차피 멸망할 세상 때문에?!`,JPN:`他の実験体のため？　世界のため？　どうせ滅亡するのに！？`,ENG:`Is it because of the test subjects? Or the world that's going to end anyway?!`,TWN:`是因為實驗體嗎？還是因為始終都會毀滅的世界？`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`SENA_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`뻔한 질문이네. 대답해 줘 봤자 이해하지도 못할 거면서.`,JPN:`くだらない質問ね。答えてあげても理解できないくせに。`,ENG:`What stupid questions. Even if I answer them, you wouldn't understand.`,TWN:`愚蠢的問題，就算我回答，你也沒辦法理解的。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`우리 애들을 지켜 주기 위해서야.`,JPN:`子どもたちを守るためよ。`,ENG:`It's to protect my kids.`,TWN:`是因為要保護我的孩子們。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`narration`,speaker:null,text:{KOREA:`나는…. 류드밀라를, 너희들을 잃고 싶지 않았어.`,JPN:`私は……リュドミラを、あなたたちを失いたくなかった。`,ENG:`I didn't want... to lose Lyudmila. I didn't want to lose you all.`,TWN:`我…不想失去盧德米拉，還有你們。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L28_1`,type:`narration`,speaker:null,text:{KOREA:`단 한 사람도.`,JPN:`誰一人も。`,ENG:`Not even a single soul.`,TWN:`一個人也不想失去。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L30_1`,type:`dialog`,speaker:`SENA_HARMONY_NULL_NULL`,text:{KOREA:`너희들은 어차피 틀에 찍혀 나온 소모품이잖아?`,JPN:`あなたたちはどうせ型から作られた消耗品でしょう？`,ENG:`But you're all expendables produced in molds!`,TWN:`你們也只不過是量產的消耗品而已！`},stage:{bg:`BLACK`,slots:{L:{char_id:`SENA_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}}];export{e as default};